-- Seeds the four conditions linked from the home hero that were missing from the
-- disorder table (schizoaffective-disorder, panic-disorder, adhd, social-anxiety).
-- Safe to re-run: uses "on conflict (slug) do nothing".
-- Run in the Supabase SQL Editor.
-- Educational content only — not medical advice.

insert into public.disorder (
  name,
  slug,
  category,
  short_description,
  overview,
  who_is_affected,
  neurochemistry,
  biological_causes,
  environmental_causes,
  psychological_causes,
  lifestyle_causes,
  symptoms,
  medications,
  lifestyle_remedies,
  prognosis,
  prevalence,
  related_disorders
)
values
  (
    'Panic Disorder',
    'panic-disorder',
    'anxiety',
    'Recurrent, unexpected panic attacks and persistent worry about having more of them.',
    'Panic disorder involves sudden surges of intense fear or discomfort — panic attacks — that peak within minutes and are accompanied by strong physical sensations such as a racing heart, shortness of breath, dizziness, or a feeling of unreality. Over time, the fear of having another attack can become its own problem, leading people to avoid places or situations where escape feels hard. Panic attacks are not dangerous in themselves, and the condition responds well to evidence-based care.',
    'Panic disorder often begins in late adolescence or early adulthood and is more common in people with a family history of anxiety, a temperament that is highly sensitive to bodily sensations, or significant life stress. Major transitions, loss, illness, or periods of sleep deprivation and high caffeine intake can precede a first attack.',
    'Panic involves the brain''s threat-detection system — especially the amygdala and brainstem alarm circuits — firing as if there were immediate danger. Norepinephrine, serotonin, GABA, and carbon-dioxide sensitivity all play a role. The body launches a full fight-or-flight response (adrenaline, faster heart and breathing), and the mind then interprets those sensations as a sign of catastrophe, which amplifies the alarm.',
    '["Inherited sensitivity in the brain''s alarm and stress-response systems.", "Heightened sensitivity to internal body sensations such as heart rate and breathing changes.", "Caffeine, nicotine, and stimulant sensitivity that can trigger or worsen attacks.", "Medical conditions (thyroid problems, arrhythmias, respiratory issues) that can mimic or set off panic."]',
    '["Major life stress, loss, or transition close to the onset of the first attacks.", "Trauma or a history of feeling unsafe or out of control.", "Stimulant or substance use, including withdrawal states."]',
    '["Catastrophic interpretation of normal body sensations (for example, reading a fast heartbeat as a heart attack).", "Fear of fear: anxiety about having another attack keeps the alarm system primed.", "Avoidance of places where a previous attack happened, which reinforces the fear over time."]',
    '["High caffeine intake, poor sleep, and irregular routines that raise baseline arousal.", "Avoiding feared situations, which prevents the brain from learning they are safe.", "Hyperventilation or chronic shallow breathing that lowers carbon dioxide and triggers symptoms."]',
    '[{"name": "Panic attacks", "severity": "severe", "description": "Sudden episodes of intense fear with a pounding heart, sweating, trembling, shortness of breath, or chest tightness that peak within minutes.", "why_it_occurs": "The fight-or-flight response fires fully and quickly, flooding the body with adrenaline even though there is no real external threat."}, {"name": "Fear of future attacks", "severity": "moderate", "description": "Persistent worry between attacks about when the next one will happen.", "why_it_occurs": "The brain links ordinary sensations to danger, so it stays on alert for early warning signs."}, {"name": "Avoidance behavior", "severity": "moderate", "description": "Avoiding places, activities, or situations associated with previous attacks.", "why_it_occurs": "Avoidance reduces fear briefly but teaches the brain those situations are genuinely dangerous."}, {"name": "Physical symptoms", "severity": "moderate", "description": "Dizziness, numbness, nausea, depersonalization, or a feeling of choking during attacks.", "why_it_occurs": "Rapid breathing and adrenaline change blood chemistry and blood flow, producing strange but harmless sensations."}]',
    '[{"name": "SSRIs", "type": "Antidepressant", "mechanism": "Increase serotonin signaling over time, reducing the frequency and intensity of panic attacks.", "best_for": "First-line treatment for ongoing panic disorder.", "common_side_effects": ["nausea", "sleep changes", "headache", "sexual side effects"]}, {"name": "SNRIs", "type": "Antidepressant", "mechanism": "Act on serotonin and norepinephrine pathways involved in mood and arousal.", "best_for": "Panic disorder, especially with co-occurring depression.", "common_side_effects": ["nausea", "sweating", "blood pressure changes"]}, {"name": "Benzodiazepines", "type": "Anxiolytic", "mechanism": "Boost GABA activity for rapid, short-term calming of acute anxiety.", "best_for": "Short-term or as-needed relief under close medical supervision due to dependence risk.", "common_side_effects": ["drowsiness", "reduced coordination", "dependence with prolonged use"]}]',
    '["Learn that panic attacks are intense but not dangerous, and that they always pass.", "Practice slow diaphragmatic breathing to counter hyperventilation.", "Use gradual exposure to feared sensations and situations so the brain relearns safety.", "Reduce caffeine, nicotine, and other stimulants.", "Keep sleep and daily routines consistent to lower baseline arousal."]',
    'Panic disorder is highly treatable. Cognitive behavioral therapy — especially interoceptive exposure — and medication when appropriate help most people substantially reduce or eliminate attacks. Relapse prevention focuses on continuing skills, limiting avoidance, and managing stress and sleep.',
    'Affects roughly 2-3% of adults in a given year.',
    '["Generalized Anxiety Disorder", "Social Anxiety Disorder", "Agoraphobia", "Major Depressive Disorder"]'
  ),
  (
    'Social Anxiety Disorder',
    'social-anxiety',
    'anxiety',
    'Intense fear of being judged, embarrassed, or scrutinized in social situations.',
    'Social anxiety disorder is more than shyness. It is a persistent, intense fear of social or performance situations in which a person worries about being judged, humiliated, or rejected. The anxiety can be so strong that people avoid everyday interactions — speaking up, eating in public, making calls, or meeting new people — which can limit relationships, education, and work. With therapy and, when appropriate, medication, most people improve significantly.',
    'Social anxiety often starts in childhood or the teenage years. Risk is higher for people with an inhibited or shy temperament, a family history of anxiety, early experiences of criticism, bullying, or embarrassment, and cultures or environments that place heavy emphasis on social evaluation.',
    'Social anxiety involves an overactive threat response to signals of social judgment, with the amygdala reacting strongly to faces, eye contact, and perceived disapproval. Serotonin, dopamine, and norepinephrine systems are involved, and the prefrontal cortex may struggle to down-regulate the alarm during social situations.',
    '["Inherited, inhibited temperament and a sensitive threat-detection system.", "Heightened physiological reactivity (blushing, sweating, trembling) that becomes a focus of fear.", "Family history of anxiety disorders."]',
    '["Childhood teasing, bullying, criticism, or humiliating experiences.", "Overprotective or highly critical caregiving that emphasizes how others judge you.", "Limited early opportunities to practice social skills and build confidence."]',
    '["Excessive self-focus and monitoring of one''s own performance during interactions.", "Predicting rejection or embarrassment before it happens.", "Interpreting neutral reactions as negative, and harshly reviewing interactions afterward."]',
    '["Avoiding social situations, which prevents disconfirming the feared outcome.", "Using alcohol to cope, which can worsen anxiety over time.", "Safety behaviors (avoiding eye contact, rehearsing every word) that maintain the fear."]',
    '[{"name": "Fear of social situations", "severity": "moderate", "description": "Marked anxiety about situations where one might be observed or judged, such as speaking, meeting people, or performing.", "why_it_occurs": "The brain treats social evaluation as a serious threat, activating the same alarm system used for physical danger."}, {"name": "Physical symptoms", "severity": "moderate", "description": "Blushing, sweating, trembling, racing heart, or nausea before or during social events.", "why_it_occurs": "The fight-or-flight response prepares the body for threat, and these visible signs often become a new source of worry."}, {"name": "Avoidance", "severity": "moderate", "description": "Avoiding or enduring feared situations with intense distress, or relying on safety behaviors.", "why_it_occurs": "Avoidance lowers anxiety in the moment but prevents learning that feared outcomes rarely happen."}, {"name": "Anticipatory anxiety", "severity": "moderate", "description": "Worrying for days or weeks before an upcoming social event.", "why_it_occurs": "Mentally rehearsing worst-case scenarios keeps the threat system activated long before the event."}]',
    '[{"name": "SSRIs", "type": "Antidepressant", "mechanism": "Increase serotonin signaling, reducing social fear and avoidance over weeks.", "best_for": "First-line medication treatment for social anxiety disorder.", "common_side_effects": ["nausea", "sleep changes", "headache", "sexual side effects"]}, {"name": "SNRIs", "type": "Antidepressant", "mechanism": "Act on serotonin and norepinephrine pathways tied to mood and arousal.", "best_for": "Social anxiety, particularly with co-occurring depression.", "common_side_effects": ["nausea", "sweating", "blood pressure changes"]}, {"name": "Beta-blockers", "type": "Performance-anxiety aid", "mechanism": "Blunt the physical symptoms of anxiety such as a racing heart and trembling.", "best_for": "Specific performance situations like public speaking, taken as needed.", "common_side_effects": ["fatigue", "cold hands", "low blood pressure"]}]',
    '["Use gradual, repeated exposure to feared social situations to build confidence.", "Shift attention outward onto the conversation rather than monitoring yourself.", "Drop safety behaviors so the brain can learn that feared outcomes rarely occur.", "Practice self-compassion and realistic appraisal of how others actually respond.", "Limit alcohol as a coping tool, which tends to worsen anxiety over time."]',
    'Social anxiety disorder responds well to cognitive behavioral therapy, particularly exposure-based approaches, and to medication when needed. Many people achieve lasting improvement, though continued practice with social situations helps prevent old avoidance patterns from returning.',
    'One of the most common anxiety disorders, affecting roughly 7% of adults in a given year.',
    '["Generalized Anxiety Disorder", "Panic Disorder", "Avoidant Personality Patterns", "Major Depressive Disorder"]'
  ),
  (
    'Attention-Deficit/Hyperactivity Disorder (ADHD)',
    'adhd',
    'neurodevelopmental',
    'A neurodevelopmental condition affecting attention, impulse control, and activity regulation.',
    'ADHD is a neurodevelopmental condition characterized by ongoing patterns of inattention, hyperactivity, and impulsivity that interfere with functioning or development. It is not a matter of laziness or lack of willpower — it reflects differences in how the brain regulates attention, motivation, and self-control. ADHD often continues into adulthood, where it may look more like restlessness, disorganization, and difficulty with follow-through. With understanding, structure, skills, and treatment, people with ADHD can thrive.',
    'ADHD usually appears in childhood, though it is sometimes recognized later, especially in people whose inattentive symptoms were overlooked. It is strongly heritable and affects all genders, though presentation can differ. Co-occurring conditions such as anxiety, depression, and learning differences are common.',
    'ADHD involves differences in dopamine and norepinephrine signaling within networks that support attention, motivation, working memory, and impulse control — particularly the prefrontal cortex and its connections. These differences make it harder to sustain effort on tasks that are not immediately rewarding and to filter distractions.',
    '["Strong genetic and heritable component.", "Differences in dopamine and norepinephrine signaling in attention and reward networks.", "Prenatal exposures (such as tobacco or alcohol), prematurity, or low birth weight in some cases.", "Differences in the development and connectivity of prefrontal and related brain regions."]',
    '["Chaotic or highly unstructured environments that strain weak self-regulation.", "Sleep deprivation, which worsens attention and impulse control.", "High-demand settings without external structure or support."]',
    '["Difficulty with self-directed motivation for non-preferred tasks.", "Weak working memory and time perception, leading to procrastination and missed deadlines.", "Emotional dysregulation and low frustration tolerance in some people."]',
    '["Irregular sleep and screen-heavy routines that reduce attention capacity.", "Lack of external structure, reminders, or accountability.", "Overcommitment without systems to manage tasks and time."]',
    '[{"name": "Inattention", "severity": "moderate", "description": "Difficulty sustaining focus, following through, organizing tasks, and avoiding careless mistakes.", "why_it_occurs": "Attention and working-memory networks struggle to maintain effort on tasks that lack immediate reward or novelty."}, {"name": "Hyperactivity", "severity": "moderate", "description": "Restlessness, fidgeting, difficulty staying seated, or a constant sense of being driven; in adults, often inner restlessness.", "why_it_occurs": "Under-stimulated reward and arousal systems seek movement and input to stay engaged."}, {"name": "Impulsivity", "severity": "moderate", "description": "Acting without thinking, interrupting, difficulty waiting, or making hasty decisions.", "why_it_occurs": "Reduced top-down control from the prefrontal cortex makes it harder to pause between impulse and action."}, {"name": "Executive dysfunction", "severity": "moderate", "description": "Trouble with planning, prioritizing, time management, and starting or finishing tasks.", "why_it_occurs": "The brain systems that coordinate goal-directed behavior over time work less consistently."}]',
    '[{"name": "Stimulants", "type": "Stimulant medication", "mechanism": "Increase dopamine and norepinephrine availability, improving focus, impulse control, and follow-through.", "best_for": "First-line treatment for ADHD in many children and adults.", "common_side_effects": ["reduced appetite", "sleep changes", "increased heart rate", "irritability"]}, {"name": "Non-stimulants (e.g., atomoxetine)", "type": "Non-stimulant", "mechanism": "Increase norepinephrine signaling to support attention and impulse control.", "best_for": "People who do not tolerate stimulants or have certain co-occurring conditions.", "common_side_effects": ["fatigue", "nausea", "appetite changes", "mood changes"]}, {"name": "Alpha-2 agonists (e.g., guanfacine)", "type": "Non-stimulant", "mechanism": "Act on prefrontal receptors to improve regulation and reduce hyperactivity.", "best_for": "Hyperactivity, impulsivity, or as an add-on, especially in children.", "common_side_effects": ["drowsiness", "low blood pressure", "dry mouth"]}]',
    '["Use external structure: calendars, reminders, checklists, and consistent routines.", "Break tasks into small, concrete steps with built-in deadlines and accountability.", "Reduce distractions in the environment and use timers to sustain focus.", "Protect sleep, exercise, and regular meals, which strongly affect attention.", "Build skills through coaching or behavioral therapy alongside medication when appropriate."]',
    'ADHD is a lifelong difference for most people, but symptoms and impact can be managed well. A combination of medication, skills, structure, and accommodations helps most people improve focus, organization, and follow-through. Many people with ADHD do best by designing environments and routines that work with their brain rather than against it.',
    'Affects roughly 5% of children and around 2.5% of adults.',
    '["Generalized Anxiety Disorder", "Major Depressive Disorder", "Learning Disorders", "Oppositional and Conduct Difficulties"]'
  ),
  (
    'Schizoaffective Disorder',
    'schizoaffective-disorder',
    'psychotic',
    'A condition combining features of psychosis with significant mood episodes.',
    'Schizoaffective disorder involves a combination of psychotic symptoms — such as hallucinations or delusions — and major mood episodes (depression, mania, or both). It sits between schizophrenia and mood disorders: psychotic symptoms are present for some time even without a mood episode, but mood episodes are also prominent over the course of the illness. Because it blends two symptom domains, treatment usually addresses both. With coordinated care, many people achieve meaningful stability and recovery.',
    'Schizoaffective disorder typically emerges in late adolescence through early adulthood. Risk is shaped by genetic vulnerability, early developmental and prenatal factors, significant stress or trauma, and substance use in vulnerable individuals. Having risk factors does not guarantee the condition will develop.',
    'The disorder involves dysregulation of dopamine signaling (linked to psychosis and salience) alongside the serotonin, norepinephrine, and other systems implicated in mood episodes. Glutamate, stress hormones, sleep and circadian disruption, and differences in brain connectivity also contribute to both the psychotic and mood features.',
    '["Genetic vulnerability overlapping with both schizophrenia and mood disorders.", "Dysregulation of dopamine alongside mood-related neurotransmitter systems.", "Early neurodevelopmental or prenatal stressors in some people.", "Sleep and circadian disruption that can worsen both psychosis and mood symptoms."]',
    '["High stress, trauma, social adversity, or isolation in vulnerable individuals.", "Cannabis or stimulant use that can trigger or worsen psychosis.", "Unstable housing, conflict, or major life disruption that complicates recovery."]',
    '["Distressing interpretations of unusual perceptions, fueling fear and withdrawal.", "Stigma and self-stigma that reduce help-seeking and increase isolation.", "Cognitive overload that makes it harder to organize thoughts during episodes."]',
    '["Stopping medication abruptly without clinical guidance, which raises relapse risk.", "Irregular sleep, high stress, and substance use that destabilize symptoms.", "Lack of routine, meaningful activity, and social connection."]',
    '[{"name": "Psychotic symptoms", "severity": "severe", "description": "Hallucinations, delusions, or disorganized thinking that occur, at times, independent of mood episodes.", "why_it_occurs": "Dysregulated dopamine and salience networks generate or assign undue importance to internal experiences."}, {"name": "Mood episodes", "severity": "severe", "description": "Periods of major depression, mania, or both, with prominent changes in mood, energy, and activity.", "why_it_occurs": "Mood-regulating neurotransmitter systems and stress chemistry shift the baseline of mood and drive."}, {"name": "Disorganized thinking", "severity": "moderate", "description": "Speech or thought that becomes hard to follow, tangential, or loosely connected.", "why_it_occurs": "Executive-control and language networks struggle to sequence thoughts under cognitive load."}, {"name": "Functional and cognitive difficulties", "severity": "moderate", "description": "Problems with motivation, attention, memory, and daily functioning between or during episodes.", "why_it_occurs": "Both psychosis and mood disturbance can tax the brain systems supporting goal-directed behavior."}]',
    '[{"name": "Antipsychotics", "type": "Antipsychotic", "mechanism": "Reduce dopamine D2 signaling to lessen hallucinations, delusions, and relapse risk.", "best_for": "Core treatment for the psychotic features of schizoaffective disorder.", "common_side_effects": ["weight gain", "metabolic changes", "sedation", "movement symptoms"]}, {"name": "Mood stabilizers", "type": "Mood stabilizer", "mechanism": "Stabilize mood and reduce the frequency and intensity of mood episodes.", "best_for": "The bipolar type, or where manic or mixed episodes are prominent.", "common_side_effects": ["tremor", "weight changes", "thyroid or kidney effects (with some agents)", "fatigue"]}, {"name": "Antidepressants", "type": "Antidepressant", "mechanism": "Support serotonin and related signaling to treat depressive episodes, often combined with an antipsychotic.", "best_for": "The depressive type, used carefully under specialist guidance.", "common_side_effects": ["nausea", "sleep changes", "sexual side effects"]}]',
    '["Build a relapse-prevention plan listing early warning signs, contacts, and crisis resources.", "Prioritize consistent sleep and low-disruption routines.", "Avoid cannabis, stimulants, and other substances that can worsen symptoms.", "Use coordinated specialty care, psychoeducation, and supported work or education.", "Reduce isolation with structured, low-pressure social contact and practical support."]',
    'Outcomes vary, but coordinated treatment of both psychotic and mood symptoms helps many people achieve substantial stability. Early intervention, tolerable medication, family or community support, substance avoidance, and meaningful roles improve recovery and relapse prevention. Urgent help is needed when symptoms create danger, severe agitation, or suicidal thoughts.',
    'Estimated lifetime prevalence around 0.3%.',
    '["Schizophrenia", "Bipolar Disorder", "Major Depressive Disorder", "Delusional Disorder"]'
  ),
  (
    'Bipolar Disorder',
    'bipolar-disorder',
    'mood',
    'A mood disorder marked by episodes of mania or hypomania alternating with depression.',
    'Bipolar disorder is a mood condition involving distinct episodes of elevated mood — mania or the milder hypomania — and, for most people, episodes of depression. During manic phases, energy, activity, confidence, and impulsivity rise sharply; during depressive phases, mood, energy, and motivation fall. Between episodes, many people feel stable. Because mania can impair judgment and depression can be severe, accurate diagnosis and consistent treatment matter a great deal, and most people achieve good stability with the right plan.',
    'Bipolar disorder usually emerges in late adolescence or early adulthood. It is strongly heritable, and risk is shaped by genetics, sleep and circadian disruption, significant stress, trauma, and substance use. Episodes can be triggered by sleep loss, major life changes, or certain medications.',
    'Bipolar disorder involves dysregulation across mood, reward, and circadian systems, with shifts in dopamine, serotonin, norepinephrine, and glutamate signaling. Disrupted sleep-wake and circadian rhythms are closely tied to episode onset, and brain networks for emotion regulation and impulse control function differently during mood episodes.',
    '["Strong genetic and heritable vulnerability.", "Dysregulation of dopamine, serotonin, and other mood-related neurotransmitter systems.", "Circadian rhythm and sleep-wake instability that can trigger episodes.", "Sensitivity to certain medications and substances that can provoke mania."]',
    '["Major life stress, loss, or disruptive change.", "Sleep deprivation or significant schedule disruption.", "Substance use, including stimulants and alcohol, that can destabilize mood."]',
    '["Difficulty recognizing early warning signs of an oncoming episode.", "Beliefs or behaviors during hypomania that feel productive but escalate risk.", "Stigma and self-criticism that can deepen depressive phases."]',
    '["Irregular sleep and inconsistent daily routines.", "Stopping medication when feeling well, which raises relapse risk.", "Overcommitment and high stimulation that can tip mood upward."]',
    '[{"name": "Manic episodes", "severity": "severe", "description": "Periods of elevated or irritable mood with increased energy, reduced need for sleep, racing thoughts, and impulsive or risky behavior.", "why_it_occurs": "Reward and arousal systems become over-activated while regulation networks struggle to rein them in."}, {"name": "Hypomanic episodes", "severity": "moderate", "description": "Milder elevation in mood and energy that is noticeable to others but does not cause major impairment or psychosis.", "why_it_occurs": "A less extreme version of the same shift in mood and reward signaling seen in mania."}, {"name": "Depressive episodes", "severity": "severe", "description": "Low mood, loss of interest, fatigue, changes in sleep and appetite, and difficulty concentrating.", "why_it_occurs": "Mood, reward, and energy systems shift downward, often alongside disrupted sleep and stress chemistry."}, {"name": "Mood instability", "severity": "moderate", "description": "Shifts in energy, sleep, and emotion between episodes, sometimes with mixed features.", "why_it_occurs": "Underlying circadian and emotion-regulation systems remain sensitive to stress and sleep changes."}]',
    '[{"name": "Mood stabilizers (e.g., lithium)", "type": "Mood stabilizer", "mechanism": "Stabilize mood and reduce the frequency and intensity of manic and depressive episodes.", "best_for": "Long-term maintenance and reducing relapse and suicide risk.", "common_side_effects": ["tremor", "increased thirst", "thyroid or kidney effects", "weight changes"]}, {"name": "Antipsychotics", "type": "Antipsychotic", "mechanism": "Reduce dopamine signaling to calm manic symptoms and, for some agents, treat bipolar depression.", "best_for": "Acute mania, mixed states, or maintenance.", "common_side_effects": ["weight gain", "metabolic changes", "sedation", "movement symptoms"]}, {"name": "Anticonvulsant mood stabilizers", "type": "Mood stabilizer", "mechanism": "Stabilize neuronal excitability to help prevent episodes.", "best_for": "Maintenance, rapid cycling, or when lithium is not suitable.", "common_side_effects": ["dizziness", "sedation", "rash (with some agents)", "weight changes"]}]',
    '["Keep a highly consistent sleep and daily routine to protect circadian rhythm.", "Track mood, sleep, and early warning signs to catch episodes early.", "Build a relapse-prevention plan with trusted contacts and clear steps.", "Limit alcohol and stimulants that can destabilize mood.", "Continue maintenance treatment even when feeling well, under clinical guidance."]',
    'Bipolar disorder is a long-term condition, but most people achieve substantial stability with consistent treatment, routine, and monitoring. Combining medication with psychoeducation, therapy, sleep regulation, and relapse prevention reduces episode frequency and severity. Urgent help is needed during severe mania, psychosis, or suicidal thoughts.',
    'Affects roughly 1-2% of adults over the lifetime.',
    '["Major Depressive Disorder", "Schizoaffective Disorder", "Generalized Anxiety Disorder", "Attention-Deficit/Hyperactivity Disorder (ADHD)"]'
  ),
  (
    'Post-Traumatic Stress Disorder (PTSD)',
    'ptsd',
    'other',
    'A trauma- and stressor-related condition that can develop after a frightening or overwhelming event.',
    'Post-traumatic stress disorder can develop after experiencing or witnessing a traumatic event such as violence, an accident, disaster, abuse, or combat. It involves re-experiencing the trauma through intrusive memories or nightmares, avoiding reminders, persistent negative changes in mood and thinking, and a heightened state of alertness. These responses are the nervous system''s attempt to protect against further danger, but they keep the threat alarm switched on long after the event has passed. Effective trauma-focused treatments exist and help many people recover.',
    'PTSD can affect anyone who has experienced trauma, though not everyone who experiences trauma develops it. Risk is higher with more severe or repeated trauma, lack of support afterward, prior trauma or mental health conditions, and ongoing stress. Children, first responders, survivors of violence, and military personnel are among those at elevated risk.',
    'PTSD involves an overactive amygdala (threat detection), an under-regulating prefrontal cortex, and a hippocampus that struggles to file memories as past rather than present. Stress hormones such as cortisol and adrenaline, along with norepinephrine and other systems, keep the body primed for danger and make trauma memories feel vivid and immediate.',
    '["Differences in stress-hormone regulation and threat-response sensitivity.", "Prior trauma or existing mental health vulnerability.", "Genetic factors influencing stress reactivity.", "Sleep disruption that impairs emotional processing and memory."]',
    '["Severe, prolonged, or repeated traumatic experiences.", "Lack of social support or safety after the event.", "Ongoing stress, instability, or reminders of the trauma."]',
    '["Beliefs of persistent danger, self-blame, or a foreshortened future.", "Avoidance of reminders, which prevents the memory from being processed.", "Difficulty trusting others or feeling safe."]',
    '["Sleep deprivation that worsens hyperarousal and intrusive memories.", "Substance use to numb distress, which interferes with recovery.", "Isolation that reduces support and reinforces threat beliefs."]',
    '[{"name": "Intrusive memories", "severity": "severe", "description": "Unwanted recollections, flashbacks, or nightmares that make the trauma feel like it is happening again.", "why_it_occurs": "The brain stores the trauma as an unresolved present threat, so reminders reactivate it vividly."}, {"name": "Avoidance", "severity": "moderate", "description": "Avoiding people, places, thoughts, or feelings that recall the trauma.", "why_it_occurs": "Avoidance reduces distress briefly but prevents the memory from being processed and updated as past."}, {"name": "Negative changes in mood and thinking", "severity": "moderate", "description": "Persistent fear, guilt, shame, detachment, or a bleak view of oneself and the world.", "why_it_occurs": "Trauma can reshape beliefs about safety, trust, and self-worth and dampen positive emotion."}, {"name": "Hyperarousal", "severity": "moderate", "description": "Being easily startled, on edge, irritable, or unable to sleep or concentrate.", "why_it_occurs": "The threat-detection system stays activated, keeping the body ready for danger."}]',
    '[{"name": "SSRIs", "type": "Antidepressant", "mechanism": "Increase serotonin signaling, reducing intrusive symptoms, avoidance, and hyperarousal.", "best_for": "First-line medication treatment for PTSD.", "common_side_effects": ["nausea", "sleep changes", "headache", "sexual side effects"]}, {"name": "SNRIs", "type": "Antidepressant", "mechanism": "Act on serotonin and norepinephrine pathways involved in mood and arousal.", "best_for": "PTSD, especially with prominent depression.", "common_side_effects": ["nausea", "sweating", "blood pressure changes"]}, {"name": "Prazosin", "type": "Adrenergic blocker", "mechanism": "Reduces norepinephrine effects to lessen trauma-related nightmares and sleep disturbance.", "best_for": "Nightmares and sleep problems in PTSD.", "common_side_effects": ["dizziness", "low blood pressure", "headache"]}]',
    '["Engage in trauma-focused therapy such as prolonged exposure, CPT, or EMDR.", "Build safety, routine, and supportive relationships.", "Use grounding and slow breathing to manage hyperarousal in the moment.", "Protect sleep, which is central to emotional processing.", "Limit alcohol and substances used to numb distress."]',
    'PTSD is treatable, and trauma-focused therapies help many people recover or substantially improve. Recovery is often gradual, with progress measured by less avoidance, calmer arousal, and trauma memories that feel like the past. Early support and treatment improve outcomes; ongoing symptoms deserve professional care.',
    'Estimated lifetime prevalence around 6-8% of adults.',
    '["Major Depressive Disorder", "Generalized Anxiety Disorder", "Panic Disorder", "Obsessive-Compulsive Disorder"]'
  ),
  (
    'Obsessive-Compulsive Disorder (OCD)',
    'ocd',
    'anxiety',
    'A condition involving intrusive obsessions and repetitive compulsions performed to reduce distress.',
    'Obsessive-compulsive disorder involves obsessions — unwanted, intrusive thoughts, images, or urges that cause distress — and compulsions, which are repetitive behaviors or mental acts performed to reduce that distress or prevent a feared outcome. The relief is temporary, so the cycle repeats and can consume hours each day. OCD is not about being tidy or particular; the thoughts are distressing and unwanted. It responds well to specialized therapy and, when appropriate, medication.',
    'OCD often begins in childhood, adolescence, or early adulthood. Risk is influenced by genetics, brain-circuit differences, temperament, and sometimes stressful or triggering life events. It affects all genders and can fluctuate in severity over time.',
    'OCD involves overactivity in a brain loop connecting the orbitofrontal cortex, anterior cingulate, and basal ganglia (striatum), which can generate persistent "something is wrong" signals. Serotonin and glutamate signaling are implicated, which is why serotonergic medications often help and why the brain struggles to switch off the urge to check, wash, or repeat.',
    '["Genetic and heritable vulnerability.", "Differences in serotonin and glutamate signaling.", "Overactivity in cortico-striatal brain circuits tied to error and threat detection.", "In some children, symptom onset following certain infections (a debated, specific subset)."]',
    '["Stressful or triggering life events that intensify symptoms.", "Reinforcement when compulsions briefly relieve anxiety.", "Family accommodation of rituals that can inadvertently maintain them."]',
    '["Inflated sense of responsibility and overestimation of threat.", "Belief that thoughts are dangerous or must be controlled.", "Need for certainty and intolerance of doubt that drives checking and reassurance."]',
    '["Engaging in rituals and reassurance-seeking that strengthen the cycle.", "Avoiding triggers, which prevents learning that feared outcomes are unlikely.", "Sleep loss and high stress that worsen symptom intensity."]',
